ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  jsonrpc: "2.0",
  id:      vars.rpcId,
  result: {
    protocolVersion: "2025-03-26",
    serverInfo: {
      name:    "atelier-mcp-mdm",
      version: "1.0.0"
    },
    capabilities: {
      tools: {
        listChanged: false
      }
    }
  }
}

%dw 2.0
output application/json
var resultBody = payload.result default {}
var isError = (payload.status default "") == "error"
---
{
  jsonrpc: "2.0",
  id:      vars.rpcId,
  result: {
    content: [
      {
        "type": "text",
        text:   write(resultBody, "application/json")
      }
    ],
    isError: isError
  }
}

%dw 2.0
output application/json
---
{
  jsonrpc: "2.0",
  id:      vars.rpcId,
  error: {
    code:    -32601,
    message: "Method not found: " ++ (vars.rpcMethod default "")
  }
}

%dw 2.0
output application/json
---
{
  status: "error",
  tool:   vars.toolName,
  result: { code: "UNKNOWN_TOOL", message: "tool not supported: " ++ (vars.toolName default "") }
}

%dw 2.0
output application/json
---
{
  tools: [
    {
      name: "resolve_supplier",
      description: "サプライヤー名/ヒントから ゴールデン ID を解決する。matched=false でも success で返す。",
      inputSchema: {
        "type": "object",
        properties: {
          supplierName: { "type": "string", description: "サプライヤー名(例: 関西部品)" },
          hint:         { "type": "string", description: "追加文脈 [地域名、業種など]" }
        },
        required: ["supplierName"]
      }
    },
    {
      name: "get_supplier_relations",
      description: "ゴールデン ID から親会社・子会社・過去インシデント・代替部品候補を取得する。",
      inputSchema: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string", description: "ゴールデン ID(例: G-KANSAI-PARTS-001)" },
          depth:            { "type": "integer", description: "関係の深さ(任意・既定 1、最大 2)" }
        },
        required: ["supplierGoldenId"]
      }
    },
    {
      name: "update_supplier_risk_score",
      description: "サプライヤーのリスクスコア(0..1)を更新する。previousRiskScore を返す。",
      inputSchema: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string" },
          riskScore:        { "type": "number", description: "新しいスコア [0..1]" },
          reason:           { "type": "string", description: "更新理由(任意)" },
          incidentId:       { "type": "string", description: "紐付ける Incident__c.Name(任意)" }
        },
        required: ["supplierGoldenId", "riskScore"]
      }
    },
    {
      name: "update_ontology",
      description: "Knowledge Graph に subject/predicate/object のトリプルを記録する。tripleId を返す。",
      inputSchema: {
        "type": "object",
        properties: {
          subject:    { "type": "string", description: "主語(例: ゴールデン ID)" },
          predicate:  { "type": "string", description: "述語(例: hasRiskFactor)" },
          "object":   { "type": "string", description: "目的語" },
          incidentId: { "type": "string", description: "紐付ける Incident__c.Name(任意)" }
        },
        required: ["subject", "predicate", "object"]
      }
    },
    {
      name: "list_suppliers",
      description: "条件指定 (region / status / リスクスコア範囲 / limit) でアクティブな取引先一覧を返す。region 未指定なら全 region。",
      inputSchema: {
        "type": "object",
        properties: {
          region:       { "type": "string", description: "Region__c の値 (例: 関西、 中部、 兵庫)。 完全一致。" },
          status:       { "type": "string", description: "ACTIVE / INACTIVE / BLOCKED / ALL (既定 ACTIVE)" },
          riskScoreMin: { "type": "number", description: "0..1 の下限。 省略時は無制限。" },
          riskScoreMax: { "type": "number", description: "0..1 の上限。 省略時は無制限。" },
          limit:        { "type": "integer", description: "1..200 (既定 50)" }
        },
        required: []
      }
    },
    {
      name: "list_regions",
      description: "Supplier__c.Region__c に登録されているユニーク値と、各 region の ACTIVE 取引先件数を返す。",
      inputSchema: {
        "type": "object",
        properties: {},
        required: []
      }
    },
    {
      name: "list_parts",
      description: "条件指定 (supplierGoldenId / category / location / nameLike / limit) で部品一覧を返す (READ-ONLY)。 既定 limit=10、 上限 50。 truncated=true なら絞り込み推奨。",
      inputSchema: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string", description: "PrimarySupplier__c の GoldenId__c (例: G-TOHOKU-MET-001)。 完全一致。" },
          category:         { "type": "string", description: "電力設備 / 機械部品 / 電子部品 / 素材 のいずれか。" },
          location:         { "type": "string", description: "倉庫拠点コード (例: KOBE-W1)。 完全一致。" },
          nameLike:         { "type": "string", description: "部品番号の部分一致 (例: TOH-500)。" },
          limit:            { "type": "integer", description: "1..50 (既定 10)" }
        },
        required: []
      }
    },
    {
      name: "resolve_part",
      description: "部品番号 (Part__c.Name) から部品詳細を 1 件解決 (READ-ONLY)。 在庫 / リードタイム / 主たるサプライヤー / 代替候補数を返す。",
      inputSchema: {
        "type": "object",
        properties: {
          partNumber: { "type": "string", description: "部品番号 (例: P-2024-TOH-500)。 完全一致。" }
        },
        required: ["partNumber"]
      }
    },
    {
      name: "list_part_alternatives",
      description: "部品の代替品一覧を取得 (READ-ONLY)。 CompatibilityScore DESC で並ぶ。",
      inputSchema: {
        "type": "object",
        properties: {
          partNumber: { "type": "string", description: "オリジナル部品番号 (例: P-2024-TOH-500)。" },
          limit:      { "type": "integer", description: "1..50 (既定 10)" }
        },
        required: ["partNumber"]
      }
    },
    {
      name: "find_suppliers_for_part",
      description: "部品を供給可能なサプライヤー一覧 (主+代替経由) を返す (READ-ONLY)。 RiskScore ASC (低リスク優先) で並ぶ。 source='PRIMARY' or 'ALTERNATIVE'。",
      inputSchema: {
        "type": "object",
        properties: {
          partNumber: { "type": "string", description: "部品番号 (例: P-2024-TOH-500)。" },
          limit:      { "type": "integer", description: "1..50 (既定 10)" }
        },
        required: ["partNumber"]
      }
    },
    {
      name: "list_incidents",
      description: "インシデント一覧を取得 (READ-ONLY)。 ORDER BY CreatedDate DESC。 既定 limit=10、 上限 50。 truncated=true なら絞り込み推奨。",
      inputSchema: {
        "type": "object",
        properties: {
          supplierGoldenId: { "type": "string", description: "Supplier__c.GoldenId__c で絞り込み。" },
          partNumber:       { "type": "string", description: "Part__c.Name で絞り込み。" },
          status:           { "type": "string", description: "OPEN / IN_PROGRESS / RESOLVED / ALL。" },
          severity:         { "type": "string", description: "CRITICAL / HIGH / MEDIUM / LOW。" },
          since:            { "type": "string", description: "ISO8601 日付 (例: 2026-05-01)。 これ以降の CreatedDate のみ。" },
          limit:            { "type": "integer", description: "1..50 (既定 10)" }
        },
        required: []
      }
    }
  ]
}

%dw 2.0
output application/json
---
{
  tools: [
