ee:variables.ee:set-variable:
%dw 2.0
output application/java
---
if (vars.toolInput.depth != null)
  { "depth": (vars.toolInput.depth as String) }
else
  {}

%dw 2.0
output application/java
---
if (vars.toolInput.limit != null)
  { "limit": (vars.toolInput.limit as String) }
else
  {}

%dw 2.0
output application/java
---
if (vars.toolInput.limit != null)
  { "limit": (vars.toolInput.limit as String) }
else
  {}
